mapper.select:
# 左连接，左边主表，右边从表，根据主表字段 查询从表信息。
# 主表该字段 可为 空NULL，即 右边从表 可能会出现 空数据条
# SELECT sp.* from wc_issue_product sp left join
# 内连接
SELECT sp.* from wc_issue_product sp inner join
bc_sale s on s.id = sp.businessId WHERE 1 = 1 AND (sp.`businessType` = 'sell' OR sp.`businessType` = 'returned')

    AND s.`customerId` IN

        #{customerId}



    AND sp.`productId` IN

        #{productId}



    AND sp.`warehouseId` IN

        #{warehouseId}



    AND s.`sellerId` IN

        #{sellerId}



    AND s.`issueDate`  >=  #{query.startDate}


    AND s.`issueDate`   <=  #{query.endDate}

ORDER BY sp.createdTime DESC

# 用 GROUP BY 计算 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM SELECT sp.productId, sp.warehouseId, SUM(sp.quantity) as quantity, sp.price, SUM(sp.amount) as amount # 左连接 # from wc_issue_product sp left join # 内连接 from wc_issue_product sp inner join bc_sale s on s.id = sp.businessId WHERE 1 = 1 AND (sp.`businessType` = 'sell' OR sp.`businessType` = 'returned')
AND s.`customerId` IN
#{customerId}
AND sp.`productId` IN
#{productId}
AND sp.`warehouseId` IN
#{warehouseId}
AND s.`issueDate` >= #{query.startDate}
AND s.`issueDate` <= #{query.endDate}
# 用 GROUP BY 计算 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM GROUP BY sp.productId, sp.warehouseId ORDER BY sp.createdTime DESC

# 用 GROUP BY 计算 每个客户的 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM SELECT s.customerId, sp.productId, sp.warehouseId, SUM(sp.quantity) as quantity, sp.price, SUM(sp.amount) as amount # 左连接 # from wc_issue_product sp left join # 内连接 from wc_issue_product sp inner join bc_sale s on s.id = sp.businessId WHERE 1 = 1 AND (sp.`businessType` = 'sell' OR sp.`businessType` = 'returned')
AND s.`customerId` IN
#{customerId}
AND sp.`productId` IN
#{productId}
AND sp.`warehouseId` IN
#{warehouseId}
AND s.`issueDate` >= #{query.startDate}
AND s.`issueDate` <= #{query.endDate}
# 用 GROUP BY 计算 每个客户的 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM GROUP BY s.customerId, sp.productId, sp.warehouseId ORDER BY sp.createdTime DESC

# 左连接，左边主表，右边从表，根据主表字段 查询从表信息。
# 主表该字段 可为 空NULL，即 右边从表 可能会出现 空数据条
# SELECT pp.* from wc_issue_product pp left join
# 内连接
SELECT pp.* from wc_issue_product pp inner join
bc_purchase p on p.id = pp.businessId WHERE 1 = 1 AND (pp.`businessType` = 'buy' OR pp.`businessType` = 'refund')

    AND p.`supplierId` IN

        #{supplierId}



    AND pp.`productId` IN

        #{productId}



    AND pp.`warehouseId` IN

        #{warehouseId}



    AND p.`issueDate`  >=  #{query.startDate}


    AND p.`issueDate`   <=  #{query.endDate}

ORDER BY pp.createdTime DESC

# 用 GROUP BY 计算 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM SELECT pp.productId, pp.warehouseId, SUM(pp.quantity) as quantity, pp.price, SUM(pp.amount) as amount # 左连接 # from wc_issue_product pp left join # 内连接 from wc_issue_product pp inner join bc_purchase p on p.id = pp.businessId WHERE 1 = 1 AND (pp.`businessType` = 'buy' OR pp.`businessType` = 'refund')
AND p.`supplierId` IN
#{supplierId}
AND pp.`productId` IN
#{productId}
AND pp.`warehouseId` IN
#{warehouseId}
AND p.`issueDate` >= #{query.startDate}
AND p.`issueDate` <= #{query.endDate}
# 用 GROUP BY 计算 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM GROUP BY pp.productId, pp.warehouseId ORDER BY pp.createdTime DESC

# 用 GROUP BY 计算 每个供应商的 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM SELECT p.supplierId, pp.productId, pp.warehouseId, SUM(pp.quantity) as quantity, pp.price, SUM(pp.amount) as amount # 左连接 # from wc_issue_product pp left join # 内连接 from wc_issue_product pp inner join bc_purchase p on p.id = pp.businessId WHERE 1 = 1 AND (pp.`businessType` = 'buy' OR pp.`businessType` = 'refund')
AND p.`supplierId` IN
#{supplierId}
AND pp.`productId` IN
#{productId}
AND pp.`warehouseId` IN
#{warehouseId}
AND p.`issueDate` >= #{query.startDate}
AND p.`issueDate` <= #{query.endDate}
# 用 GROUP BY 计算 每个供应商的 每个产品的 每个仓库的 总数量、总金额 返回给 SELECT 的聚合参数 SUM GROUP BY p.supplierId, pp.productId, pp.warehouseId ORDER BY pp.createdTime DESC
